mapper.select:
select r.room_number as number, r.floor, r.type_id as type, rt.name as type_name, rt.price, case r.status when 'VC' then 'vacant' when 'OC' then 'occupied' when 'RS' then 'reserved' when 'VD' then 'dirty' when 'CLEANING' then 'cleaning' when 'OOO' then 'maintenance' else 'vacant' end as frontend_status, case r.status when 'VC' then '空净房' when 'OC' then '入住' when 'RS' then '预订' when 'VD' then '脏房' when 'CLEANING' then '清洁中' when 'OOO' then '维修' else '未知' end as status_name, g.name as guest_name, g.phone as guest_phone, g.checkin as guest_checkin, g.checkout as guest_checkout from room r join room_type rt on r.type_id = rt.id left join guest g on r.room_number = g.room_number and r.status = 'OC'
and r.status = #{status}
and r.floor = #{floor}
order by r.room_number
